def simple_sub_encrypt(key, message):
    mapper = {
        p: k for p, k in zip(ascii_uppercase, key)
    }
    return ''.join(mapper.get(m, m) for m in message)

def key_to_mapping(key):
    a = {
        k: p for k, p in zip(key, ascii_uppercase)
    }
    a[" "] = " "
    return a

